import static org.mockito.Mockito.*;

import java.io.IOException;

import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.Lexer;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class CSVParserCloseTest {

    @Mock
    private Lexer lexerMock;

    private CSVParser csvParser;

    @BeforeEach
    void setUp() throws Exception {
        MockitoAnnotations.openMocks(this);
        // Use reflection to create CSVParser instance with lexerMock injected
        csvParser = org.mockito.Mockito.mock(CSVParser.class, invocation -> {
            if ("close".equals(invocation.getMethod().getName())) {
                return invocation.callRealMethod();
            }
            return invocation.callRealMethod();
        });

        java.lang.reflect.Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(csvParser, lexerMock);
    }

    @Test
    void close_callsLexerClose_whenLexerNotNull() throws IOException, Exception {
        csvParser.close();
        verify(lexerMock, times(1)).close();
    }

    @Test
    void close_doesNotThrow_whenLexerIsNull() throws IOException, Exception {
        java.lang.reflect.Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(csvParser, null);
        csvParser.close();
        // no exception means pass
    }
}
